BK = BraidGroup(K);  gK = list(BK.generators())
rows = []
for perm in iter_perms(range(_sage_const_1 , K+_sage_const_1 )):
    sp   = SagePerm(list(perm))
    b    = BK.one()
    for i in sp.reduced_word(): b = b * gK[i-_sage_const_1 ]
    btr  = float(b.burau_matrix()(t=QQ(_sage_const_1 )/QQ(_sage_const_2 )).trace())
    ct   = list(sp.cycle_type())          # e.g. [3,2,1]
    dist = compute_dist([x-_sage_const_1  for x in perm], K)
    rows.append({
        "perm"          : list(perm),
        "label"         : "".join(str(x) for x in perm),
        "burau"         : btr,
        "writhe"        : len(sp.reduced_word()),
        "max_cycle_len" : int(max(ct)),
        "n_cycles"      : len(ct),
        "n_fixed"       : int(ct.count(_sage_const_1 )),
        "ct_str"        : str(ct),
        "dist"          : dist,
    })
dists = [r["dist"] for r in rows]
print(f"  完了。dist: [{min(dists):.3f}, {max(dists):.3f}]  mean={np.mean(dists):.3f}")

