# 全データ学習 → 上位 N 件選択での Precision@N
# （CV 推定ではなく "全件知っている場合" の理論上限も確認）
# ══════════════════════════════════════════════════════════════════
print("\n[Precision@N: 全データ学習後の選択精度]")
print("  ※ 全720件を学習して同720件をランキング — 過学習込みの上限値")

def oracle_top(rows, N):
    return {r["label"] for r in sorted(rows, key=lambda r: r["dist"])[:N]}

def burau_3stage_top(rows, N):
    """W-7i の 3-Stage-25% を再現"""
    all_dists = np.array([r["dist"] for r in rows])
    dist_thr  = float(np.percentile(all_dists, _sage_const_25 ))
    # cycle type の mean_dist を計算
    ct_mean = defaultdict(list)
    for r in rows: ct_mean[r["ct_str"]].append(r["dist"])
    kept_cts = {ct for ct, dv in ct_mean.items()
                if float(np.mean(dv)) <= dist_thr}
    kept = [r for r in rows if r["ct_str"] in kept_cts]
    # within-type Burau 降順
    ct_grp = defaultdict(list)
    for r in kept: ct_grp[r["ct_str"]].append(r)
    selected = []
    for ct, grp in ct_grp.items():
        bv = np.array([r["burau"] for r in grp])
        dv = np.array([r["dist"]  for r in grp])
        rr = stats.pearsonr(bv, dv)[_sage_const_0 ] if len(grp) >= _sage_const_3  else _sage_const_0p0 
        direction = -_sage_const_1  if rr > _sage_const_0  else +_sage_const_1 
        n_sel = int(max(_sage_const_1 , round(N * len(grp) / len(kept))))
        ranked = sorted(grp, key=lambda r: direction * r["burau"], reverse=True)
        selected.extend(ranked[:n_sel])
    if len(selected) > N:
        selected = sorted(selected, key=lambda r: r["dist"])[:N]
    elif len(selected) < N:
        sel_lbl = {r["label"] for r in selected}
        rem = sorted([r for r in rows if r["label"] not in sel_lbl],
                     key=lambda r: r["dist"])
        selected.extend(rem[:N - len(selected)])
    return {r["label"] for r in selected[:N]}

def global_burau_top(rows, N):
    bv = np.array([r["burau"] for r in rows])
    dv = np.array([r["dist"]  for r in rows])
    direction = -_sage_const_1  if stats.pearsonr(bv, dv)[_sage_const_0 ] > _sage_const_0  else +_sage_const_1 
    sel = sorted(rows, key=lambda r: direction * r["burau"], reverse=True)[:N]
    return {r["label"] for r in sel}

N_vals = [_sage_const_10 , _sage_const_20 , _sage_const_50 , _sage_const_100 , _sage_const_150 ]
labels_all = [r["label"] for r in rows]

# ML モデルを全データで学習してランキング
fitted = {}
for name, model in MODELS.items():
    model.fit(X, y)
    fitted[name] = model

print(f"\n  {'N_sel':<7}| {'GlobalBurau':<13}| {'3Stg-_sage_const_25 %':<13}| ", end="")
for name in MODELS: print(f"{name:<13}| ", end="")
