prec_data = {k: [] for k in ["GlobalBurau","3Stg-25%","Oracle"] + list(MODELS.keys())}
for N in N_vals:
    true_top = oracle_top(rows, N)
    p_gb  = float(len(true_top & global_burau_top(rows, N))) / N
    p_3s  = float(len(true_top & burau_3stage_top(rows, N))) / N
    line  = f"  N={N:<5}| {p_gb:.3f}        | {p_3s:.3f}        | "
    prec_data["GlobalBurau"].append(p_gb)
    prec_data["3Stg-25%"].append(p_3s)
    for name, model in fitted.items():
        y_pred = model.predict(X)
        # 予測dist が小さい順に選ぶ
        top_idx = np.argsort(y_pred)[:N]
        ml_top  = {labels_all[i] for i in top_idx}
        p_ml    = float(len(true_top & ml_top)) / N
        prec_data[name].append(p_ml)
        line += f"{p_ml:.3f}        | "
    p_or = _sage_const_1p0 
    prec_data["Oracle"].append(p_or)
    line += f"{p_or:.3f}"
    print(line)

