cv_prec = {name: {N: [] for N in N_vals} for name in MODELS}
cv_prec["GlobalBurau"] = {N: [] for N in N_vals}
cv_prec["3Stg-25%"]    = {N: [] for N in N_vals}

for fold_idx, (train_idx, test_idx) in enumerate(kf.split(X)):
    X_tr, X_te = X[train_idx], X[test_idx]
    y_tr, y_te = y[train_idx], y[test_idx]
    rows_te = [rows[i] for i in test_idx]

    for N in N_vals:
        # Oracle for this fold
        true_top_fold = oracle_top(rows_te, min(N, len(rows_te)))

        # GlobalBurau & 3-Stage on test fold
        p_gb = float(len(true_top_fold & global_burau_top(rows_te, min(N, len(rows_te))))) / min(N, len(rows_te))
        p_3s = float(len(true_top_fold & burau_3stage_top(rows_te, min(N, len(rows_te))))) / min(N, len(rows_te))
        cv_prec["GlobalBurau"][N].append(p_gb)
        cv_prec["3Stg-25%"][N].append(p_3s)

        # ML モデルを train fold で学習 → test fold でランキング
        for name, base_model in MODELS.items():
            import copy
            m = copy.deepcopy(base_model)
            m.fit(X_tr, y_tr)
            y_pred_te = m.predict(X_te)
            n_sel = min(N, len(rows_te))
            top_idx = np.argsort(y_pred_te)[:n_sel]
            ml_top  = {rows_te[i]["label"] for i in top_idx}
            p_ml    = float(len(true_top_fold & ml_top)) / n_sel
            cv_prec[name][N].append(p_ml)

print(f"\n  {'N_sel':<7}| {'GlobalBurau':<16}| {'3Stg-_sage_const_25 %':<16}| ", end="")
for name in MODELS: print(f"{name:<16}| ", end="")
