print("\n" + "=" * _sage_const_65 )
print("  総合サマリー")
print("=" * _sage_const_65 )

print(f"\n  [CV R² — dist 予測精度]")
for name, res in cv_results.items():
    bar = "█" * int(max(_sage_const_0 , res['r2_mean']) * _sage_const_30 )
    print(f"    {name:<12}: R²={res['r2_mean']:.4f}  {bar}")
print(f"    {'Linear(Burau)':<12}: R²={lr_r2.mean():.4f}  (参考: Burau単体)")

print(f"\n  [CV Precision@N=50 比較]")
ranking = []
for key in ["GlobalBurau","3Stg-25%"] + list(MODELS.keys()):
    val = float(np.mean(cv_prec[key][_sage_const_50 ]))
    ranking.append((key, val))
for key, val in sorted(ranking, key=lambda x: -x[_sage_const_1 ]):
    bar = "█" * int(val * _sage_const_30 )
    print(f"    {key:<12}: {val:.4f}  {bar}")

print(f"\n  [問いB: cycle type 系 vs Burau の特徴量重要度]")
ct_features = ["max_cycle_len","n_cycles","n_fixed"]
ct_imp_rf  = sum(rf_imp[FEATURE_NAMES.index(f)] for f in ct_features)
bur_imp_rf = rf_imp[FEATURE_NAMES.index("burau")]
print(f"    RF:      cycle_type系合計={ct_imp_rf:.4f}  Burau={bur_imp_rf:.4f}")
ct_imp_xgb  = sum(xgb_imp[FEATURE_NAMES.index(f)] for f in ct_features)
bur_imp_xgb = xgb_imp[FEATURE_NAMES.index("burau")]
print(f"    XGBoost: cycle_type系合計={ct_imp_xgb:.4f}  Burau={bur_imp_xgb:.4f}")

if ct_imp_rf > bur_imp_rf:
    print(f"\n  ★ cycle type 系特徴量が Burau より支配的 → W-7i の解析と一致")
else:
    print(f"\n  ★ Burau が cycle type 系より支配的 → 解析的発見と異なる")

print(f"\n  [結論]")
best_ml     = max(((n, float(np.mean(cv_prec[n][_sage_const_50 ]))) for n in MODELS),
                  key=lambda x: x[_sage_const_1 ])
val_3stg    = float(np.mean(cv_prec["3Stg-25%"][_sage_const_50 ]))
val_gb      = float(np.mean(cv_prec["GlobalBurau"][_sage_const_50 ]))
val_best_ml = best_ml[_sage_const_1 ]
print(f"    GlobalBurau (解析)  : Precision@50 = {val_gb:.4f}")
print(f"    3-Stage-25% (解析)  : Precision@50 = {val_3stg:.4f}")
print(f"    {best_ml[_sage_const_0 ]:<12} (ML): Precision@50 = {val_best_ml:.4f}")
if val_best_ml > val_3stg:
    print(f"    → ML ({best_ml[_sage_const_0 ]}) が 3-Stage を上回る")
elif val_best_ml > val_gb:
    print(f"    → ML ({best_ml[_sage_const_0 ]}) が GlobalBurau を上回るが 3-Stage には届かず")
else:
    print(f"    → 解析的アプローチ (3-Stage) が ML を上回る")

